#include<bits/stdc++.h>
using namespace std;

int main()
{
    priority_queue<int> q;
    int n;
    scanf("%d",&n);
    int x;
    scanf("%d",&x);
    q.push(x);
    long long ans=0;
    for(int i=2;i<=n;i++)
    {
        scanf("%d",&x);
        if(x<q.top())
        {
            ans+=q.top()-x;
            q.pop();
            q.push(x);
        }
        q.push(x);
    }
    printf("%lld",ans);
    return 0;
}
